import React, { useState, useRef, useEffect } from 'react';
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Loader2 } from 'lucide-react';

// 🚨 SPLIT KEY TRICK (Safe for GitHub)
const part1 = "AIzaSyAzJtMQSarM6NT42";
const part2 = "Zz8dUK5VM3PqW7VoWM";
const API_KEY = part1 + part2; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "🔴 DEBUG MODE: I will show you exactly what is wrong if I crash. Ask me anything!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    console.log("🚀 STARTING DIRECT API REQUEST...");
    console.log("🔑 Key Check:", API_KEY ? "Loaded (Length: " + API_KEY.length + ")" : "MISSING");

    try {
      // 1. Prepare Data
      const systemContext = `You are CampusBot for NIMIT. Answer simply.`;
      
      const payload = {
        contents: [{
          parts: [{ text: systemContext + "\n\nUser Question: " + userMsg.text }]
        }]
      };

      console.log("📦 Payload prepared:", payload);

      // 2. 🚨 DIRECT INTERNET CALL
      // We are hitting the URL directly. No libraries to mess this up.
      const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${API_KEY}`;
      
      console.log("🌐 Sending fetch request to Google...");
      const response = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      console.log("📡 Response Status:", response.status);
      const data = await response.json();
      console.log("📄 Raw Data received:", data);

      // 3. Check for specific Google Errors
      if (data.error) {
        console.error("❌ GOOGLE API ERROR:", data.error);
        throw new Error(`Google Error [${data.error.code}]: ${data.error.message}`);
      }

      // 4. Extract Answer
      if (!data.candidates || !data.candidates[0].content) {
        throw new Error("Empty response from AI (No candidates found).");
      }

      const aiResponse = data.candidates[0].content.parts[0].text;
      
      console.log("✅ Success! Answer:", aiResponse);
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: aiResponse, isBot: true }]);

    } catch (error) {
      console.error("🔥 CRITICAL FAILURE:", error);
      setIsThinking(false);
      // Print the error directly in the chat so you don't have to hunt for it
      setMessages((prev) => [...prev, { text: `🔥 DEBUG ERROR: ${error.message}`, isBot: true }]);
    }
  };

  // --- UI RENDER ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      {!isOpen && (
        <button onClick={onOpen} className="w-14 h-14 bg-red-600 rounded-full shadow-lg flex items-center justify-center border border-white/20 animate-bounce text-white">
          <Bot size={24} />
        </button>
      )}

      {isOpen && (
        <div className="w-[350px] md:w-[380px] h-[500px] bg-[#0a0a0a] border border-white/20 rounded-2xl shadow-2xl flex flex-col overflow-hidden">
          <div className="bg-red-900/50 border-b border-white/10 p-4 flex items-center justify-between">
            <span className="text-white font-bold flex items-center gap-2"><Bot size={20}/> Debug Bot</span>
            <button onClick={onClose} className="text-white"><X size={20} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[90%] p-3 text-sm rounded-xl ${msg.isBot ? 'bg-[#1a1a1a] border border-red-500/30 text-white' : 'bg-indigo-600 text-white'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 bg-black border-t border-white/10 flex gap-2">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type to test..." 
              className="flex-1 bg-[#1a1a1a] border border-white/10 rounded-lg px-3 py-2 text-sm text-white"
            />
            <button onClick={handleSend} className="bg-red-600 p-2 rounded-lg text-white"><Send size={18} /></button>
          </div>
        </div>
      )}
    </div>
  );
}

export default ChatBot;
